# tools/lint.sh - Fast semantic lint for .ddd/.mus project files
#
# Usage:
#   tools/lint.sh <project.mus>              # Human-readable output
#   tools/lint.sh <project.mus> --format json # Machine-readable JSON
#   tools/lint.sh --all                       # Lint all projects
#
# Exit codes:
#   0 - clean (no errors; warnings are non-blocking)
#   1 - errors found
#   2 - invalid arguments or missing files

set -euo pipefail

REPO_ROOT=$(cd "$(dirname "$0")/.." && pwd)
MUSCOMP="${MUSCOMP_BIN:-$REPO_ROOT/toolchain/muscomp/build/Debug/muscomp}"
FORMAT=""
ALL=false
PROJECTS=()

# Parse arguments
while [[ $# -gt 0 ]]; do
    case "$1" in
        --format)
            [[ $# -ge 2 ]] || { echo "Error: --format requires an argument (json or text)" >&2; exit 2; }
            FORMAT="$2"
            shift 2
            ;;
        --all)
            ALL=true
            shift
            ;;
        --help|-h)
            echo "Usage: tools/lint.sh [--all | <project.mus>...] [--format json]"
            echo ""
            echo "Fast semantic lint for Muscovite .ddd/.mus project files (~2s)."
            echo ""
            echo "Options:"
            echo "  --all           Lint all projects"
            echo "  --format json   Machine-readable JSON output"
            echo "  --help          Show this help"
            echo ""
            echo "Exit codes: 0=clean, 1=errors, 2=bad arguments"
            exit 0
            ;;
        -*)
            echo "Error: Unknown option: $1" >&2
            echo "Run: tools/lint.sh --help" >&2
            exit 2
            ;;
        *)
            PROJECTS+=("$1")
            shift
            ;;
    esac
done

# Validate format
if [[ -n "$FORMAT" ]] && [[ "$FORMAT" != "json" ]] && [[ "$FORMAT" != "text" ]]; then
    echo "Error: --format must be 'json' or 'text'" >&2
    exit 2
fi

# Collect projects
if [[ "$ALL" == "true" ]]; then
    for mus in "$REPO_ROOT"/toolchain/muscomp/tests/golden/*/project.mus; do
        [[ -f "$mus" ]] && PROJECTS+=("$mus")
    done
fi

if [[ ${#PROJECTS[@]} -eq 0 ]]; then
    echo "Error: No project file specified. Use --all or provide a .mus path." >&2
    echo "Run: tools/lint.sh --help" >&2
    exit 2
fi

# Validate all files exist
for p in "${PROJECTS[@]}"; do
    if [[ ! -f "$p" ]]; then
        echo "Error: Project file not found: $p" >&2
        exit 2
    fi
done

# Verify muscomp exists
if [[ ! -x "$MUSCOMP" ]]; then
    echo "Error: muscomp not found at $MUSCOMP" >&2
    echo "Build with: cd toolchain/muscomp && cmake --preset debug && cmake --build --preset debug" >&2
    exit 2
fi

# Build and run lint command
EXIT_CODE=0

if [[ ${#PROJECTS[@]} -eq 1 ]]; then
    LINT_CMD=("$MUSCOMP" --lint-only --project "${PROJECTS[0]}")
    if [[ "$FORMAT" == "json" ]]; then
        LINT_CMD+=(--json)
    fi
    "${LINT_CMD[@]}" || EXIT_CODE=$?
else
    for p in "${PROJECTS[@]}"; do
        LINT_CMD=("$MUSCOMP" --lint-only --project "$p")
        if [[ "$FORMAT" == "json" ]]; then
            LINT_CMD+=(--json)
        fi
        if ! "${LINT_CMD[@]}"; then
            EXIT_CODE=1
        fi
    done
fi

exit $EXIT_CODE
